import sqlite3; import pandas as pd; conn = sqlite3.connect('data/telemetry_demo.sqlite'); print('Tables:', pd.read_sql('SELECT name FROM sqlite_master WHERE type=''table''', conn)['name'].tolist()); print('\nRecent Decisions:'); print(pd.read_sql('SELECT timestamp_ms, contract_direction, decision, proposed_stake, q_model, q_final, regime FROM decision_events ORDER BY timestamp_ms DESC LIMIT 5', conn).to_string()); print('\nRecent Trades:'); print(pd.read_sql('SELECT * FROM executed_trades ORDER BY timestamp_ms DESC LIMIT 5', conn).to_string());
